import { useLocation, useSearchParams } from "react-router-dom"
import News from "./news"
import { useEffect, useState } from "react"
function Newsview() {
    const API_KEY_NEWS = process.env.REACT_APP_API_KEY_NEWS
    const location = useLocation()
    const selectedtopics = location.state?.selectedtopics
    let [apiprompt, changeapiprompt] = useState("")
   useEffect(() => {
        changeapiprompt(selectedtopics.map((item) => {
            return item.map((item2, index2) => {
               
                return  item2.toLowerCase() 
            })
            
        })[0].join('&'))
    })
    async function getnews() {
        let apires = await fetch("https://newsapi.org/v2/top-headlines?country=us&category=technology&health&apiKey=67b6329949b943e2b30dc71ea5274b77")
    }
    return<>
    {apiprompt}
        <p>{selectedtopics}</p>
    </>
}
export default Newsview
